import React from "react";
import { useNavigate, useLocation } from "react-router-dom";

const InteractionMode = () => {
    const navigate = useNavigate();
    const location = useLocation();

    // Retrieve the selected avatar passed via state
    const { avatar } = location.state || { avatar: null };

    return (
        <div style={{ textAlign: "center", padding: "50px" }}>
            <h1>Choose your mode of interaction</h1>
            <div style={{ display: "flex", justifyContent: "center", gap: "30px", marginTop: "30px" }}>
                {/* Interaction */}
                <div
                    onClick={() => navigate("/interaction-page")}
                    style={{
                        cursor: "pointer",
                        textAlign: "center",
                        border: "1px solid #ccc",
                        borderRadius: "10px",
                        padding: "20px",
                        width: "200px",
                    }}
                >
                    <div
                        style={{
                            width: "100%",
                            height: "150px",
                            backgroundColor: "#dfe7fd",
                            borderRadius: "8px",
                            display: "flex",
                            justifyContent: "center",
                            alignItems: "center",
                        }}
                    >
                        <p style={{ fontSize: "18px", fontWeight: "bold" }}>Interaction</p>
                    </div>
                    <p style={{ marginTop: "10px" }}>Interaction</p>
                </div>

                {/* Health Check-In */}
                <div
                    onClick={() => navigate("/health-check")}
                    style={{
                        cursor: "pointer",
                        textAlign: "center",
                        border: "1px solid #ccc",
                        borderRadius: "10px",
                        padding: "20px",
                        width: "200px",
                    }}
                >
                    {avatar ? (
                        <img
                            src={avatar.image}
                            alt={avatar.name}
                            style={{
                                width: "100%",
                                height: "150px",
                                objectFit: "cover",
                                borderRadius: "8px",
                            }}
                        />
                    ) : (
                        <div
                            style={{
                                width: "100%",
                                height: "150px",
                                backgroundColor: "#fdebd0",
                                borderRadius: "8px",
                                display: "flex",
                                justifyContent: "center",
                                alignItems: "center",
                            }}
                        >
                            <p style={{ fontSize: "18px", fontWeight: "bold" }}>Health Check-In</p>
                        </div>
                    )}
                    <p style={{ marginTop: "10px" }}>Health Check-In</p>
                </div>
            </div>
        </div>
    );
};

export default InteractionMode;
